    lag(outer_a) OVER (
        PARTITION BY (SELECT count(*) FROM foo WHERE length(b) = length(outer_b))
        ORDER BY outer_a
    )
FROM (
    SELECT a AS outer_a, b AS outer_b
    FROM foo
) as fsq
ORDER BY part, outer_a;

