        ORDER BY (SELECT count(*) FROM foo WHERE length(outer_b) > a + 2), outer_a
    )
FROM (
    SELECT a AS outer_a, b AS outer_b
    FROM foo
) as fsq
ORDER BY ord, outer_a;

